using UnityEngine;
using System.Collections.Generic;

[System.Serializable]
public class GameState
{
    public PlayerState player;
    public List<EnemyState> enemies;
    public LevelState level;
    public InventoryState inventory;
    public float playTime;
    public string saveTime;
}

[System.Serializable]
public class PlayerState
{
    public string name;
    public int health;
    public int maxHealth;
    public int level;
    public float experience;
    public int score;
    public float[] position;
    public int lives;
    public bool isAlive;
}

[System.Serializable]
public class EnemyState
{
    public string name;
    public int health;
    public int maxHealth;
    public float[] position;
    public bool isAlive;
    public string enemyType;
}

[System.Serializable]
public class LevelState
{
    public int currentLevel;
    public int currentScene;
    public int checkpointIndex;
    public float[] checkpointPosition;
    public List<string> unlockedLevels;
}

[System.Serializable]
public class InventoryState
{
    public List<ItemState> items;
    public int gold;
    public int keys;
}

[System.Serializable]
public class ItemState
{
    public string id;
    public string name;
    public int quantity;
    public bool isEquipped;
}

public class SaveSystem : MonoBehaviour
{
    private const string SAVE_KEY = "GameSave";
    private const string QUICK_SAVE_KEY = "QuickSave";

    public GameState currentState;

    void Start()
    {
        // Create initial state
        currentState = new GameState();
        CreateNewGame();
    }

    public void CreateNewGame()
    {
        // Initialize player
        currentState.player = new PlayerState();
        currentState.player.name = "Hero";
        currentState.player.health = 100;
        currentState.player.maxHealth = 100;
        currentState.player.level = 1;
        currentState.player.experience = 0f;
        currentState.player.score = 0;
        currentState.player.position = new float[] { 0, 0, 0 };
        currentState.player.lives = 3;
        currentState.player.isAlive = true;

        // Initialize level
        currentState.level = new LevelState();
        currentState.level.currentLevel = 1;
        currentState.level.currentScene = 0;
        currentState.level.checkpointIndex = 0;
        currentState.level.checkpointPosition = new float[] { 0, 0, 0 };
        currentState.level.unlockedLevels = new List<string> { "Level1" };

        // Initialize inventory
        currentState.inventory = new InventoryState();
        currentState.inventory.items = new List<ItemState>();
        currentState.inventory.gold = 50;
        currentState.inventory.keys = 0;

        // Initialize enemies
        currentState.enemies = new List<EnemyState>();

        currentState.playTime = 0f;
        currentState.saveTime = System.DateTime.Now.ToString();

        Debug.Log("New game created!");
    }

    void Update()
    {
        // Update play time
        if (currentState != null)
        {
            currentState.playTime += Time.deltaTime;
        }

        // Quick save/load with keys
        if (Input.GetKeyDown(KeyCode.F5))
        {
            QuickSave();
        }
        if (Input.GetKeyDown(KeyCode.F9))
        {
            QuickLoad();
        }
    }

    // --- Save Methods ---

    public void QuickSave()
    {
        SaveState(QUICK_SAVE_KEY);
        Debug.Log("Quick saved!");
    }

    public void QuickLoad()
    {
        LoadState(QUICK_SAVE_KEY);
        Debug.Log("Quick loaded!");
    }

    public void SaveGame()
    {
        SaveState(SAVE_KEY);
        Debug.Log("Game saved!");
    }

    public void LoadGame()
    {
        LoadState(SAVE_KEY);
        Debug.Log("Game loaded!");
    }

    private void SaveState(string key)
    {
        if (currentState == null)
        {
            Debug.LogWarning("No game state to save!");
            return;
        }

        // Update save time
        currentState.saveTime = System.DateTime.Now.ToString();

        // Serialize
        string json = JsonUtility.ToJson(currentState, true);
        PlayerPrefs.SetString(key, json);
        PlayerPrefs.Save();

        Debug.Log("State saved to " + key);
    }

    private void LoadState(string key)
    {
        if (PlayerPrefs.HasKey(key))
        {
            string json = PlayerPrefs.GetString(key);
            GameState loadedState = JsonUtility.FromJson<GameState>(json);

            if (loadedState != null)
            {
                currentState = loadedState;
                ApplyGameState();
                Debug.Log("State loaded from " + key);
                Debug.Log("Play time: " + currentState.playTime + "s");
                Debug.Log("Saved at: " + currentState.saveTime);
            }
            else
            {
                Debug.LogError("Failed to load state from " + key);
            }
        }
        else
        {
            Debug.LogWarning("No save data found for " + key);
        }
    }

    private void ApplyGameState()
    {
        // Apply player state
        // This would set player health, position, etc.
        Debug.Log("Applying game state...");

        // Update UI
        // Update player
        // Update enemies
        // Update level
    }

    // --- Individual save/load methods ---

    public void SavePlayerState(PlayerState player)
    {
        if (currentState != null)
        {
            currentState.player = player;
        }
    }

    public PlayerState LoadPlayerState()
    {
        if (currentState != null)
        {
            return currentState.player;
        }
        return null;
    }

    public void SaveInventoryState(InventoryState inventory)
    {
        if (currentState != null)
        {
            currentState.inventory = inventory;
        }
    }

    public InventoryState LoadInventoryState()
    {
        if (currentState != null)
        {
            return currentState.inventory;
        }
        return null;
    }

    public bool HasSaveData()
    {
        return PlayerPrefs.HasKey(SAVE_KEY);
    }

    public bool HasQuickSave()
    {
        return PlayerPrefs.HasKey(QUICK_SAVE_KEY);
    }
}

